#include <QPainter>
#include <QPaintEvent>

#include "graphics_palette.h"

GraphicsPalette::GraphicsPalette(QWidget *parent)
   : QWidget(parent)
{
   pal = palette();

   // Optional:
   //    The palette (by default) has a 'clear' background.  So
   //    anything drawn in the main 'canvas' will show through
   //    to the palette.  Thus, anything drawn in the 'canvas' AND
   //    the 'palette' will both be shown.
   //
   //    But use the following to set a 'background' color that
   //    is not 'clear'.
   //          setAutoFillBackground(true);
   //          pal.setColor(QPalette::Window, Qt::white);
   //    For now, leave it 'clear'.

   // Change the default application palette to 'pal'
   setPalette(pal);
}

void GraphicsPalette::update_grid()
{
    if (draw_grid)
    {
        draw_grid = false;
    }
    else
    {
        draw_grid = true;
    }

    update();
}
 
void GraphicsPalette::paintEvent(QPaintEvent *event)
{
    Q_UNUSED(event);

    QPainter painter(this);

    painter.setRenderHint(QPainter::Antialiasing, true);

    if (draw_grid)
    {
        painter.setPen(Qt::blue);

        x = width() / 2;
        y = height();

        const QLine x_axis(x, 0, x, y);

        painter.drawLine(x_axis);

        x = width();
        y = height() / 2;

        const QLine y_axis(0, y, x, y);

        painter.drawLine(y_axis);
    }
}

